// Format the incoming CAB notification into a readable message
const item = $input.first().json.body.item;
const notifiedBy = $input.first().json.body.notifiedBy || 'Qvantum NL';
const timestamp = $input.first().json.body.timestamp;
const calendarUrl = $input.first().json.body.calendarUrl || '';

const date = new Date(item.datum).toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' });
const products = [item.qg ? 'QG' : '', item.qe ? 'QE' : ''].filter(Boolean).join(', ') || 'General';

// Teams Adaptive Card format
const teamsMessage = {
  "@type": "MessageCard",
  "@context": "http://schema.org/extensions",
  "themeColor": "002656",
  "summary": `CAB Update: ${item.thema}`,
  "sections": [{
    "activityTitle": `CAB Content Update — ${item.thema}`,
    "activitySubtitle": `Flagged by ${notifiedBy}`,
    "activityImage": "",
    "facts": [
      { "name": "Date", "value": date },
      { "name": "Type", "value": item.type },
      { "name": "Channel", "value": item.kanaal },
      { "name": "Product", "value": products },
      { "name": "Status", "value": item.status },
      { "name": "Author", "value": item.auteur }
    ],
    "markdown": true,
    "text": item.omschrijving
  }]
};

// Plain text for email
const emailSubject = `[CAB] ${item.thema} — ${item.type} (${date})`;
const emailBody = `Hi,\n\nA content item has been flagged as relevant for the Communication Advisory Board:\n\n` +
  `Theme: ${item.thema}\n` +
  `Type: ${item.type}\n` +
  `Date: ${date}\n` +
  `Channel: ${item.kanaal}\n` +
  `Product: ${products}\n` +
  `Status: ${item.status}\n` +
  `Author: ${item.auteur}\n\n` +
  `Description:\n${item.omschrijving}\n\n` +
  `Flagged by: ${notifiedBy}\n` +
  (calendarUrl ? `Calendar: ${calendarUrl}\n` : '') +
  `\n---\nThis is an automated notification from the Qvantum Content Calendar.`;

return [
  {
    json: {
      teamsMessage,
      emailSubject,
      emailBody,
      item,
      notifiedBy,
      timestamp
    }
  }
];
